import type { IGomokuState } from './state'

export enum GomokuActionType {
  // Restart game.
  RESTART = '@kyokuya/gomoku/restart',

  // Reset game.
  RESET = '@kyokuya/gomoku/reset',

  // Start game.
  START = '@kyokuya/gomoku/start',

  // Pause game.
  PAUSE = '@kyokuya/gomoku/pause',

  // Resume game.
  RESUME = '@kyokuya/gomoku/resume',

  // Finish game.
  FINISH = '@kyokuya/gomoku/finish',

  // CHANGE the activated board cell.
  ACTIVE = '@kyokuya/gomoku/active',

  // Asking for a hint.
  HINT = '@kyokuya/gomoku/hint',

  // Input into a board cell.
  MOVE = '@kyokuya/gomoku/move',

  // Retract a false move.
  RETRACT = '@kyokuya/gomoku/retract',
}

export type IGomokuAction =
  | {
      type: GomokuActionType.RESTART
    }
  | {
      type: GomokuActionType.RESET
      payload: Partial<Pick<IGomokuState, 'GOMOKU_SIZE'>>
    }
  | {
      type: GomokuActionType.START
    }
  | {
      type: GomokuActionType.PAUSE
    }
  | {
      type: GomokuActionType.RESUME
    }
  | {
      type: GomokuActionType.FINISH
      payload: number // Id of the winner.
    }
  | {
      type: GomokuActionType.HINT
    }
  | {
      type: GomokuActionType.ACTIVE
      payload: { r: number; c: number }
    }
  | {
      type: GomokuActionType.MOVE
      payload: { r: number; c: number }
    }
  | { type: GomokuActionType.RETRACT }
