import type { GomokuPlayerType, IGomokuAction } from '@kyokuya/react-game-gomoku-core'

export enum GomokuGameActionType {
  // Reset game.
  RESET_PLAYERS = '@kyokuya/gomoku/game/reset-players',

  // Swap offense and defense
  FLIP = '@kyokuya/gomoku/game/flip',
}

export type IGomokuGameAction =
  | IGomokuAction
  | {
      type: GomokuGameActionType.RESET_PLAYERS
      payload: {
        playerId: number
        playerName?: string
        playerType?: GomokuPlayerType
      }
    }
  | {
      type: GomokuGameActionType.FLIP
    }
